import { useState } from 'react';
import API from '../services/api';

function BankLogin({ onLoginSuccess }) {
  const [accountId, setAccountId] = useState('');
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPin, setShowPin] = useState(false);

  const handleLogin = async (e) => {
    e.preventDefault();
    
    if (!accountId || !pin) {
      setError('Account ID and PIN are required');
      return;
    }

    try {
      setLoading(true);
      setError('');

      // For bank demo, validate account exists
      const res = await API.get(`/account/${accountId}/balance`);
      
      if (res.status === 200) {
        onLoginSuccess(accountId);
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid Account ID or PIN');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container d-flex justify-content-center align-items-center min-vh-100">
      <div className="card shadow" style={{ width: '100%', maxWidth: '400px' }}>
        <div className="card-header bg-primary text-white">
          <h5 className="mb-0">🏦 Bank Payment Portal</h5>
        </div>
        <div className="card-body">
          {error && (
            <div className="alert alert-danger alert-dismissible fade show" role="alert">
              {error}
              <button type="button" className="btn-close" onClick={() => setError('')}></button>
            </div>
          )}

          <form onSubmit={handleLogin}>
            <div className="mb-3">
              <label className="form-label">Account ID</label>
              <input
                type="text"
                className="form-control"
                value={accountId}
                onChange={(e) => setAccountId(e.target.value)}
                placeholder="Enter your account ID"
                disabled={loading}
              />
            </div>

            <div className="mb-3">
              <label className="form-label">PIN</label>
              <div className="input-group">
                <input
                  type={showPin ? 'text' : 'password'}
                  className="form-control"
                  value={pin}
                  onChange={(e) => setPin(e.target.value)}
                  placeholder="Enter your 4-digit PIN"
                  disabled={loading}
                />
                <button
                  type="button"
                  className="btn btn-outline-secondary"
                  onClick={() => setShowPin(!showPin)}
                  disabled={loading}
                >
                  {showPin ? '👁️' : '🔒'}
                </button>
              </div>
            </div>

            <button
              type="submit"
              className="btn btn-primary w-100"
              disabled={loading}
            >
              {loading ? '🔄 Logging in...' : '🔓 Login'}
            </button>
          </form>

          <hr />
          <div className="alert alert-info small mb-0">
            <strong>Demo Account:</strong><br />
            Account ID: ACCT001<br />
            PIN: 1111
          </div>
        </div>
      </div>
    </div>
  );
}

export default BankLogin;
